Use MSTest's **`[DynamicData]`** with parameterized tests. Each new case becomes a single line instead of a whole method:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Validation.Tests;

[TestClass]
public sealed class InputValidatorTests
{
    private static IEnumerable<object[]> InvalidInputCases =>
    [
        [null, "Input cannot be empty"],
        ["", "Input cannot be empty"],
        ["   ", "Input cannot be empty"],
        ["ab", "Input must be at least 3 characters"],
        [new string('x', 256), "Input must not exceed 255 characters"],
        ["hello<script>", "Input contains invalid characters"],
    ];

    private static IEnumerable<object[]> ValidInputCases =>
    [
        ["hello-world"],
        ["abc"],
        [new string('a', 255)],
    ];

    [DataTestMethod]
    [DynamicData(nameof(InvalidInputCases))]
    public void Validate_InvalidInput_ReturnsFalse(string input, string expectedError)
    {
        var validator = new InputValidator();
        var result = validator.Validate(input);
        Assert.IsFalse(result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    [DataTestMethod]
    [DynamicData(nameof(ValidInputCases))]
    public void Validate_ValidInput_ReturnsTrue(string input)
    {
        var validator = new InputValidator();
        var result = validator.Validate(input);
        Assert.IsTrue(result.IsValid);
        Assert.IsNull(result.ErrorMessage);
    }
}
```

**Key benefits:**
- Adding a test case = adding **one line** to the data array
- `[DynamicData]` over `[DataRow]` because some inputs (`new string(...)`) aren't compile-time constants
- Two methods cover all cases: one for invalid, one for valid
- Each data row still shows as a **separate test** in the test runner
